const raw = $json.body ?? $json;
const project = raw.project;
const executionId = raw.executionId;
const outputFields = project?.output_fields ?? (raw.outputFields ?? (raw.fields ?? []).map((field_name) => ({ field_name, extract_hint: '' })));
const urls = project?.website_urls ?? raw.urls ?? [];

return urls.map((startUrl) => ({
  json: {
    jobId: raw.jobId,
    executionId,
    project,
    startUrl,
    outputFields,
    directions: project?.main_prompt ?? raw.prompt ?? '',
    summarizePrompt: project?.summarize_prompt ?? raw.summarizePrompt ?? '',
    fieldPrompt: project?.field_extract_prompt ?? raw.fieldPrompt ?? '',
    localLlmModel: project?.local_llm ?? raw.localLlmModel ?? 'gemma4:e4b',
    scraperBaseUrl: raw.scraperBaseUrl ?? 'http://simple-scraper:3000',
    totalUrls: urls.length,
  },
}));

const ctx = $('Split URLs').item.json;
const pages = $json.pages ?? [];
return [{
  json: {
    ...ctx,
    pages,
    pageCount: pages.length,
  },
}];

const config = $('After Spider').first().json;
return [{
  json: {
    jobId: config.jobId,
    executionId: config.executionId,
    startUrl: config.startUrl,
    results: [],
    scraperBaseUrl: config.scraperBaseUrl,
    emptySite: true,
  },
}];

const config = $('After Spider').first().json;
const pages = config.pages ?? [];

return pages.map((pageUrl) => ({
  json: {
    jobId: config.jobId,
    executionId: config.executionId,
    project: config.project,
    startUrl: config.startUrl,
    pageUrl,
    outputFields: config.outputFields,
    directions: config.directions,
    summarizePrompt: config.summarizePrompt,
    fieldPrompt: config.fieldPrompt,
    localLlmModel: config.localLlmModel,
    scraperBaseUrl: config.scraperBaseUrl,
  },
}));

const pages = $input.all().map((item) => item.json);

return Promise.all(pages.map(async (page) => {
  const body = { url: page.pageUrl };
  if (page.executionId) {
    body.execution_id = page.executionId;
  }
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: page.scraperBaseUrl + '/api/workflow/scrape-page',
    body,
    json: true,
  });
  if (page.executionId && !response.scrape_id) {
    throw new Error('scrape-page did not return scrape_id for ' + page.pageUrl);
  }
  return {
    json: {
      ...page,
      text: response.text ?? '',
      textLength: response.textLength ?? (response.text?.length ?? 0),
      scrapedUrl: response.url ?? page.pageUrl,
      scrape_id: response.scrape_id ?? null,
      scrape_date: response.scrape_date ?? null,
    },
  };
}));

const pages = $input.all().map((item) => item.json);

return Promise.all(pages.map(async (page) => {
  if (!page.text?.trim()) {
    throw new Error('No scraped text for ' + page.pageUrl);
  }
  const body = {
    text: page.text,
    directions: page.directions,
    localLlmModel: page.localLlmModel,
  };
  if (page.summarizePrompt) body.summarizePrompt = page.summarizePrompt;
  if (page.fieldPrompt) body.fieldPrompt = page.fieldPrompt;
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: page.scraperBaseUrl + '/api/workflow/summarize',
    body,
    json: true,
    timeout: 1800000,
  });
  return {
    json: {
      ...page,
      summary: response.summary,
      summaryLength: response.summaryLength,
    },
  };
}));

const pages = $input.all().map((item) => item.json);

return Promise.all(pages.map(async (page) => {
  if (!page.scrape_id) {
    throw new Error('Missing scrape_id for ' + page.pageUrl + ' — rebuild simple-scraper and re-import the workflow');
  }
  if (!page.executionId) {
    throw new Error('Missing executionId for ' + page.pageUrl);
  }
  const saved = await this.helpers.httpRequest({
    method: 'POST',
    url: page.scraperBaseUrl + '/api/workflow/save-scrape',
    body: {
      scrape_id: page.scrape_id,
      execution_id: page.executionId,
      page_url: page.pageUrl,
      scraped_text: page.text ?? '',
      summarized_text: page.summary ?? '',
    },
    json: true,
  });
  return {
    json: {
      ...page,
      scrape_id: saved.scrape_id ?? page.scrape_id,
      scrape_date: saved.scrape_date ?? page.scrape_date,
    },
  };
}));

const page = $json;
const outputFields = page.outputFields ?? [];

return outputFields.map((fieldDef) => ({
  json: {
    ...page,
    field: fieldDef.field_name,
    extractHint: fieldDef.extract_hint ?? '',
  },
}));

const items = $input.all().map((item) => item.json);
const config = $('After Spider').first()?.json ?? items[0] ?? {};
const outputFields = config.outputFields ?? [];
const requestedFields = outputFields.map((f) => f.field_name);

if (items.length === 0) {
  return [{
    json: {
      jobId: config.jobId,
      executionId: config.executionId,
      startUrl: config.startUrl,
      requestedFields,
      results: [],
      findings: [],
      pageResults: [],
      scraperBaseUrl: config.scraperBaseUrl,
      emptySite: true,
    },
  }];
}

const findings = [];
const results = [];
const byPage = new Map();

for (const item of items) {
  if (!byPage.has(item.pageUrl)) {
    byPage.set(item.pageUrl, {
      pageUrl: item.pageUrl,
      summary: item.summary,
      fields: [],
    });
  }
  const present = item.present === true;
  byPage.get(item.pageUrl).fields.push({
    field: item.field,
    value: present ? item.value : null,
    confidence: item.confidence ?? 'unknown',
    sourcePages: present ? [item.pageUrl] : [],
  });
  if (present) {
    findings.push({
      field: item.field,
      value: String(item.value),
      pageUrl: item.pageUrl,
      confidence: item.confidence,
    });
    results.push({
      page_url: item.pageUrl,
      field_name: item.field,
      field_value: String(item.value),
    });
  }
}

const first = items[0];
return [{
  json: {
    jobId: first.jobId,
    executionId: first.executionId,
    startUrl: first.startUrl,
    requestedFields,
    results,
    findings,
    pageResults: Array.from(byPage.values()),
    scraperBaseUrl: first.scraperBaseUrl,
    emptySite: false,
  },
}];

const saved = $json;
const source = $('Aggregate Results').first()?.json ?? $('Prepare Empty Save').first()?.json ?? $('After Spider').first()?.json;
const emptySite = Boolean(source?.emptySite);
return [{
  json: {
    jobId: source.jobId,
    executionId: source.executionId,
    scraperBaseUrl: source.scraperBaseUrl,
    startUrl: source.startUrl,
    resultsCount: saved.resultsCount ?? 0,
    message: emptySite
      ? 'No pages scraped for ' + source.startUrl
      : 'Saved ' + (saved.resultsCount ?? 0) + ' result(s) to execution ' + source.executionId,
    level: emptySite ? 'warn' : 'success',
  },
}];
